<section class="admin-head"><div class="container"><div><span class="eyebrow">MAISON CONTROL ROOM</span><h1>Dashboard</h1></div><a class="btn btn-light" href="<?= site_url('admin/products/create') ?>"><i class="bi bi-plus-lg me-2"></i>Add product</a></div></section><section class="container admin-content"><div class="row g-3 stats-row"><div class="col-md-4"><div class="stat-card"><i class="bi bi-bag"></i><div><strong><?= $stats['products'] ?></strong><span>Active products</span></div></div></div><div class="col-md-4"><div class="stat-card"><i class="bi bi-camera"></i><div><strong><?= $stats['tryons'] ?></strong><span>Saved try-ons</span></div></div></div><div class="col-md-4"><div class="stat-card"><i class="bi bi-people"></i><div><strong><?= $stats['users'] ?></strong><span>Members</span></div></div></div></div><div class="admin-card mt-4"><div class="admin-card-head"><h2>Product collection</h2><span><?= count($products) ?> total</span></div><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Product</th><th>Category</th><th>Price</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($products as $p): ?><tr><td><div class="admin-product"><img src="<?= product_image_url($p['product_image']) ?>"><strong><?= html_escape($p['name']) ?></strong></div></td><td><?= html_escape($p['category']) ?></td><td><?= money($p['price']) ?></td><td><span class="status-pill <?= $p['status']?'active':'' ?>"><?= $p['status']?'Active':'Draft' ?></span></td><td class="text-end"><a class="btn btn-sm btn-outline-ink" href="<?= site_url('admin/products/edit/'.$p['id']) ?>">Edit</a><form class="d-inline" method="post" action="<?= site_url('admin/products/delete/'.$p['id']) ?>" onsubmit="return confirm('Delete this product?')"><?= form_hidden($this->security->get_csrf_token_name(), $this->security->get_csrf_hash()) ?><button class="btn btn-sm btn-link text-danger">Delete</button></form></td></tr><?php endforeach ?></tbody></table></div></div><div class="admin